#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#include <math.h>
#define INF 1e9
#define MAX 100

struct Node {
    int x, y;
    double hardness;
};

struct PriorityQueue {
    struct Node* nodes;
    int size;
    int capacity;
};

struct PriorityQueue* createPriorityQueue(int capacity) {
    struct PriorityQueue* pq = (struct PriorityQueue*)malloc(sizeof(struct PriorityQueue));
    pq->nodes = (struct Node*)malloc(sizeof(struct Node) * capacity);
    pq->size = 0;
    pq->capacity = capacity;
    return pq;
}

void insert(struct PriorityQueue* pq, struct Node node) {
    if (pq->size == pq->capacity) {
        printf("Priority queue is full\n");
        return;
    }
    pq->nodes[pq->size] = node;
    pq->size++;
}

struct Node extractMin(struct PriorityQueue* pq) {
    if (pq->size == 0) {
        printf("Priority queue is empty\n");
        exit(1);
    }
    struct Node minNode = pq->nodes[0];
    for (int i = 1; i < pq->size; i++) {
        if (pq->nodes[i].hardness < minNode.hardness) {
            minNode = pq->nodes[i];
        }
    }
    for (int i = 0; i < pq->size - 1; i++) {
        pq->nodes[i] = pq->nodes[i + 1];
    }
    pq->size--;
    return minNode;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int r, c;
        scanf("%d %d", &r, &c);
        double heights[r][c];
        for (int i = 0; i < r; i++) {
            for (int j = 0; j < c; j++) {
                scanf("%lf", &heights[i][j]);
            }
        }
        int q;
        scanf("%d", &q);
        printf("Case %d:\n", t + 1);
        for (int i = 0; i < q; i++) {
            int i_s, j_s, i_e, j_e;
            scanf("%d %d %d %d", &i_s, &j_s, &i_e, &j_e);
            i_s--; j_s--; i_e--; j_e--;
            double minHardness[r][c];
            for (int x = 0; x < r; x++) {
                for (int y = 0; y < c; y++) {
                    minHardness[x][y] = INF;
                }
            }
            minHardness[i_s][j_s] = 0;
            struct PriorityQueue* pq = createPriorityQueue(r * c);
            struct Node node;
            node.x = i_s;
            node.y = j_s;
            node.hardness = 0;
            insert(pq, node);
            while (pq->size > 0) {
                struct Node currentNode = extractMin(pq);
                if (currentNode.x == i_e && currentNode.y == j_e) {
                    printf("%.6f\n", currentNode.hardness);
                    break;
                }
                int dx[] = {-1, 1, 0, 0};
                int dy[] = {0, 0, -1, 1};
                for (int j = 0; j < 4; j++) {
                    int x = currentNode.x + dx[j];
                    int y = currentNode.y + dy[j];
                    if (x >= 0 && x < r && y >= 0 && y < c) {
                        double hardness = currentNode.hardness;
                        if (heights[currentNode.x][currentNode.y] > heights[x][y]) {
                            hardness += 0.5 + 0.5 * sqrt(1 + pow(heights[currentNode.x][currentNode.y] - heights[x][y], 2));
                        } else {
                            hardness += -0.5 + 1.5 * sqrt(1 + pow(heights[currentNode.x][currentNode.y] - heights[x][y], 2));
                        }
                        if (hardness < minHardness[x][y]) {
                            minHardness[x][y] = hardness;
                            node.x = x;
                            node.y = y;
                            node.hardness = hardness;
                            insert(pq, node);
                        }
                    }
                }
            }
        }
        return 0;
    }

