// COMPLETE, COMPILABLE Java code
import java.util.PriorityQueue;
import java.util.Scanner;
import java.util.Comparator;

public class Main {
    static class Node {
        int x, y;
        double hardness;
        Node(int x, int y, double hardness) {
            this.x = x;
            this.y = y;
            this.hardness = hardness;
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        for (int t = 0; t < T; t++) {
            int r = sc.nextInt();
            int c = sc.nextInt();
            double[][] heights = new double[r][c];
            for (int i = 0; i < r; i++) {
                for (int j = 0; j < c; j++) {
                    heights[i][j] = sc.nextDouble();
                }
            }
            int q = sc.nextInt();
            System.out.println("Case " + (t + 1) + ":");
            for (int i = 0; i < q; i++) {
                int i_s = sc.nextInt() - 1;
                int j_s = sc.nextInt() - 1;
                int i_e = sc.nextInt() - 1;
                int j_e = sc.nextInt() - 1;
                double[][] minHardness = new double[r][c];
                for (int x = 0; x < r; x++) {
                    for (int y = 0; y < c; y++) {
                        minHardness[x][y] = Double.MAX_VALUE;
                    }
                }
                minHardness[i_s][j_s] = 0;
                PriorityQueue<Node> pq = new PriorityQueue<>(new Comparator<Node>() {
                    @Override
                    public int compare(Node a, Node b) {
                        return Double.compare(a.hardness, b.hardness);
                    }
                });
                pq.add(new Node(i_s, j_s, 0));
                while (!pq.isEmpty()) {
                    Node currentNode = pq.poll();
                    if (currentNode.x == i_e && currentNode.y == j_e) {
                        System.out.printf("%.6f\n", currentNode.hardness);
                        break;
                    }
                    int dx[] = {-1, 1, 0, 0};
                    int dy[] = {0, 0, -1, 1};
                    for (int j = 0; j < 4; j++) {
                        int x = currentNode.x + dx[j];
                        int y = currentNode.y + dy[j];
                        if (x >= 0 && x < r && y >= 0 && y < c) {
                            double hardness = currentNode.hardness;
                            if (heights[currentNode.x][currentNode.y] > heights[x][y]) {
                                hardness += 0.5 + 0.5 * Math.sqrt(1 + Math.pow(heights[currentNode.x][currentNode.y] - heights[x][y], 2));
                            } else {
                                hardness += -0.5 + 1.5 * Math.sqrt(1 + Math.pow(heights[currentNode.x][currentNode.y] - heights[x][y], 2));
                            }
                            if (hardness < minHardness[x][y]) {
                                minHardness[x][y] = hardness;
                                pq.add(new Node(x, y, hardness));
                            }
                        }
                    }
                }
            }
        }
    }
}

