                            newHardness += -0.5 + 1.5 * (1 + (heights[x][y] - heights[nx][ny]) ** 2) ** 0.5
                        if newHardness < minHardness[nx][ny]:
                            minHardness[nx][ny] = newHardness
                            heapq.heappush(pq, (newHardness, nx, ny))

